def main():
    db=json.load(open(DB,encoding="utf-8"))
    n=0; tot_raw=tot_scr=0
    for r in db:
        if r["id"] in FULL:
            r["script"]=FULL[r["id"]]
            # role_hint 재생성 위해 enrich가 다시 중립화하도록 마커 제거(각 줄에 role_hint 없음)
            n+=1
            raw=len((r.get("transcript_raw") or "").replace(" ",""))
            scr=sum(len(l["line"].replace(" ","")) for l in FULL[r["id"]])
            tot_raw+=raw; tot_scr+=scr
    json.dump(db,open(DB,"w",encoding="utf-8"),ensure_ascii=False,indent=1)
    print(f"풀대본 재작성: {n}편 | 평균 보존율 {tot_scr/tot_raw:.0%}")

if __name__=="__main__": main()
